import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Settings, Pencil, Trash2, ShieldCheck, ShieldOff, Lock, CheckCircle, Plus } from "lucide-react";
import { toast } from "sonner";
import { appSettingsService, type AppSettingPayload } from "@/api/appSettingsService";
import { getApiErrorMessage } from "@/api/app/apiError";
import { queryKeys } from '@/lib/queryKeys';
import type { AppSetting } from "@/types/settings";
import { HarmonyTable, type HarmonyColumn } from "@/components/ui/harmony-table";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { HarmonyAlertDialog } from "@/components/ui/harmony-alert-dialog";
import HarmonyForm from "@/components/forms/HarmonyForm";
import { HarmonyRichTextCell } from "@/components/ui/harmony-table-richtext-cell";
import { useHarmonyServerTable } from "@/hooks/useHarmonyServerTable";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";
import { Badge } from "@/shadcn/components/ui/badge";
import { Button } from "@/shadcn/components/ui/button";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/shadcn/components/ui/tooltip";


function AppSettingsTable() {
  const queryClient = useQueryClient();
  const [search,         setSearch]         = useState("");
  const [createOpen,     setCreateOpen]     = useState(false);
  const [editTarget,     setEditTarget]     = useState<AppSetting | null>(null);
  const [deleteTarget,   setDeleteTarget]   = useState<AppSetting | null>(null);

  const server = useHarmonyServerTable();

  const { data, isLoading, isError, error } = useQuery({
    queryKey: queryKeys.appSettings.list(server.pageIndex, server.pageSize, search),
    queryFn:  () => appSettingsService.getAppSettings(server.pageIndex, server.pageSize, search || undefined),
    staleTime: 5 * 60 * 1000,
  });

  const invalidate = () => queryClient.invalidateQueries({ queryKey: queryKeys.appSettings.base() });

  const createMutation = useMutation({
    mutationFn: (payload: AppSettingPayload) => appSettingsService.createAppSetting(payload),
    onSuccess: () => { invalidate(); setCreateOpen(false); toast.success("Setting created"); },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to create setting")),
  });

  const updateMutation = useMutation({
    mutationFn: ({ key, payload }: { key: string; payload: Partial<AppSettingPayload> }) =>
      appSettingsService.updateAppSetting(key, payload),
    onSuccess: () => { invalidate(); setEditTarget(null); toast.success("Setting updated"); },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to update setting")),
  });

  const deleteMutation = useMutation({
    mutationFn: (key: string) => appSettingsService.deleteAppSetting(key),
    onSuccess: () => { invalidate(); setDeleteTarget(null); toast.success("Setting deleted"); },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to delete setting")),
  });


  const actionsColumn: HarmonyColumn<AppSetting> = {
    key: "actions",
    header: "Actions",
    width: 80,
    sortable: false,
    resizable: false,
    cellClass: "rdg-cell-actions",
    renderCell: ({ row }) => (
      <TooltipProvider>
        <div className="flex items-center gap-0.5">
          <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update}>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-foreground"
                  disabled={!!row.isReadOnly}
                  onClick={(e) => { e.stopPropagation(); setEditTarget(row); }}
                >
                  <Pencil size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent>
                {row.isReadOnly ? "Read-only — cannot be edited" : "Edit"}
              </TooltipContent>
            </Tooltip>
          </PermissionGate>
          <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update}>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                  disabled={!!row.isReadOnly}
                  onClick={(e) => { e.stopPropagation(); setDeleteTarget(row); }}
                >
                  <Trash2 size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent>
                {row.isReadOnly ? "Read-only — cannot be deleted" : "Delete"}
              </TooltipContent>
            </Tooltip>
          </PermissionGate>
        </div>
      </TooltipProvider>
    ),
  };

  const columns: HarmonyColumn<AppSetting>[] = [
    {
      key: "id",
      header: "ID",
      width: 100,
      sortable: false,
      renderCell: ({ row }) => row.id ?? "—",
    },
    {
      key: "category",
      header: "Category",
      width: 140,
      sortParam: "category",
      renderCell: ({ row }) => row.category
        ? <Badge variant="outline">{row.category}</Badge>
        : "—",
    },
    {
      key: "key",
      header: "Key",
      width: 280,
      sortParam: "key",
      renderCell: ({ row }) => row.key,
    },
    {
      key: "value",
      header: "Value",
      width: 180,
      sortParam: "value",
      renderCell: ({ row }) => row.value ?? <span className="italic">null</span>,
    },
    {
      key: "description",
      header: "Description",
      fill: true,
      sortable: false,
      renderCell: ({ row }) => <HarmonyRichTextCell html={row.description} />,
    },
    {
      key: "isEncrypted",
      header: "Encrypted",
      width: 110,
      sortable: false,
      renderCell: ({ row }) => row.isEncrypted ? (
        <span className="flex items-center gap-1.5 text-primary">
          <ShieldCheck size={13} /> Encrypted
        </span>
      ) : (
        <span className="flex items-center gap-1.5 text-muted-foreground">
          <ShieldOff size={13} /> Plain
        </span>
      ),
    },
    {
      key: "isReadOnly",
      header: "Read Only",
      width: 110,
      sortable: false,
      renderCell: ({ row }) => row.isReadOnly ? (
        <span className="flex items-center gap-1.5 text-muted-foreground">
          <Lock size={12} /> Read Only
        </span>
      ) : (
        <span className="flex items-center gap-1.5 text-muted-foreground">
          <CheckCircle size={12} /> Editable
        </span>
      ),
    },
    actionsColumn,
  ];

  return (
    <>
      <HarmonyTable<AppSetting>
        rows={data?.data ?? []}
        columns={columns}
        rowKeyGetter={row => row.id}
        loading={isLoading}
        error={isError ? (error as Error) : undefined}

        onSearchChange={(q) => { setSearch(q); server.setPageIndex(1); }}
        searchDebounce={400}
        searchPlaceholder="Search settings…"

        dataActions={{
          extra: (
            <PermissionGate permission={PERMISSIONS.ApplicationSettings.Update}>
              <Button size="sm" onClick={() => setCreateOpen(true)}>
                <Plus size={14} /> New Setting
              </Button>
            </PermissionGate>
          ),
        }}

        pagination={server.getPagination(data)}
      />

      {/* ── Create ──────────────────────────────────────────────────────────── */}
      <HarmonyDialog
        open={createOpen}
        onOpenChange={setCreateOpen}
        title="New Application Setting"
      >
        <HarmonyForm
          dtoName="ApplicationSettingDTO"
          mode="create"
          onSubmit={(formData) => createMutation.mutate(formData as unknown as AppSettingPayload)}
          isPending={createMutation.isPending}
          onCancel={() => setCreateOpen(false)}
          submitLabel="Create Setting"
        />
      </HarmonyDialog>

      {/* ── Edit ────────────────────────────────────────────────────────────── */}
      <HarmonyDialog
        open={editTarget !== null}
        onOpenChange={(open) => { if (!open) setEditTarget(null); }}
        title={editTarget ? `Edit: ${editTarget.key}` : "Edit Setting"}
      >
        {editTarget && (
          <HarmonyForm
            dtoName="ApplicationSettingDTO"
            mode="edit"
            initialValues={{
              category: editTarget.category,
              key: editTarget.key,
              value: editTarget.value,
              description: editTarget.description,
              isEncrypted: editTarget.isEncrypted,
              isReadOnly: editTarget.isReadOnly,
            }}
            onSubmit={(formData) => updateMutation.mutate({ key: editTarget.key, payload: formData })}
            isPending={updateMutation.isPending}
            onCancel={() => setEditTarget(null)}
            submitLabel="Save Changes"
          />
        )}
      </HarmonyDialog>

      {/* ── Single delete ───────────────────────────────────────────────────── */}
      <HarmonyAlertDialog
        open={deleteTarget !== null}
        onOpenChange={open => { if (!open) setDeleteTarget(null); }}
        variant="danger"
        title="Delete Setting"
        description={deleteTarget
          ? `"${deleteTarget.key}" will be permanently deleted. This action cannot be undone.`
          : undefined}
        actionLabel="Delete"
        isActioning={deleteMutation.isPending}
        onAction={() => { if (deleteTarget) deleteMutation.mutate(deleteTarget.key); }}
      />

    </>
  );
}

export default function ApplicationSettings() {
  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'var(--section-padding)' }}>
      <div className="flex items-center gap-3">
        <div className="size-12 flex items-center justify-center rounded-(--radius-lg) bg-primary/10 shrink-0">
          <Settings className="w-7 h-7 text-primary" />
        </div>
        <div>
          <h1 className="page-title">Application Settings</h1>
          <p className="page-subtitle">Manage runtime configuration and application behavior.</p>
        </div>
      </div>

      <AppSettingsTable />
    </div>
  );
}
