import api from './app/client';

import type { AppSettingPayload } from '../types/dto';
import type { Pagination } from '../types/api';
import type { AppSetting } from '../types/settings';
import { AppSettingSchema, PaginatedSchema } from '../types/schemas';

export type { AppSettingPayload, AppSetting };

export const appSettingsService = {
  getAppSettings: (pageIndex?: number, pageSize?: number, search?: string): Promise<Pagination<AppSetting>> => {
    const params = new URLSearchParams()
    if (pageIndex !== undefined) params.set('pageIndex', String(pageIndex))
    if (pageSize !== undefined) params.set('pageSize', String(pageSize))
    if (search)                 params.set('search', search)
    const qs = params.toString()
    return api.get(`/application-settings${qs ? `?${qs}` : ''}`)
      .then(r => PaginatedSchema(AppSettingSchema).parse(r.data))
  },

  getAppSettingByKey: (key: string) =>
    api.get(`/application-settings/${key}`).then(r => r.data),

  createAppSetting: (data: AppSettingPayload) =>
    api.post('/application-settings', data).then(r => r.data),

  updateAppSetting: (key: string, data: Partial<AppSettingPayload>) =>
    api.put(`/application-settings/${key}`, data).then(r => r.data),

  deleteAppSetting: (key: string) =>
    api.delete(`/application-settings/${key}`).then(r => r.data),
};
